	public SRTP(Platform platform, int hmacAuthSizeBytes) {
		this.platform = platform;
		this.mHmacAuthSizeBytes = hmacAuthSizeBytes;
		VERBOSE = VERBOSE || SUPER_VERBOSE;
		txMasterKey = txMasterSalt = rxMasterKey = rxMasterSalt = null;
